  var dotMin = isFinite(Number(cfg.parallelDotMin)) ? Math.max(0.8, Math.min(0.99999, Number(cfg.parallelDotMin))) : 0.985;
  var nearGap = isFinite(Number(cfg.nearBboxGapMm)) ? Math.max(0, Number(cfg.nearBboxGapMm)) : 1800;
