/** лІ•м„  кұ°лҰ¬ л№Ҳ: trim(24)ліҙлӢӨ көөкІҢ мһЎм•„ лҜём„ё мҳӨн”„м…ӢВ·мӨ‘ліө лқјмқёмқ„ к°ҷмқҖ к·ёлЈ№мңјлЎң(лҹ°нғҖмһ„м—җм„ң multiRunN=0мқҙл©ҙ мҡ°м„  мғҒн–Ҙ). */
var FRAME_DEF_STEP2A_COLLINEAR_MERGE_RHO_STEP_MM = 100;
/** м¶• к°Ғ л№Ҳ(лҸ„): 4В°ліҙлӢӨ нҒ¬кІҢ н•ҳл©ҙ кұ°мқҳ нҸүн–үн•ң мЎ°к°Ғмқҙ н•ң нӮӨм—җ лӘЁмһ„. */
var FRAME_DEF_STEP2A_COLLINEAR_MERGE_AXIS_STEP_DEG = 6;
/** true: лі‘н•© gKeyм—җм„ң scope_key л¬ҙмӢң(мӣ”л“ң лҸҷмқј м§Ғм„ ). лё”лЎқВ·л°°м№ҳл§ҲлӢӨ scopeк°Җ лӢ¬лқј к№Ём§„ м„ мқҙ м•Ҳ л¬¶мқј л•Ң. falseл©ҙ кё°мЎҙмІҳлҹј мҠӨмҪ”н”„лі„ л¶„лҰ¬. */
var FRAME_DEF_STEP2A_COLLINEAR_MERGE_UNIFY_SCOPE = true;
/** true: gKeyм—җм„ң л Ҳмқҙм–ҙ к·ёлЈ№мқ„ `@`лЎң нҶөмқј вҶ’ CONC / лӢӨлҘё м„ңлёҢл Ҳмқҙм–ҙлЎң к°Ҳлқјм§„ лҸҷмқј м§Ғм„  мӨ‘мІ©лҸ„ н•ң лҚ©м–ҙлҰ¬лЎң */
var FRAME_DEF_STEP2A_COLLINEAR_MERGE_UNIFY_LAYER_GROUP = true;
/** true: rho л№Ҳ лҢҖмӢ , к°ҷмқҖ м¶•В·мҠӨмҪ”н”„В·(л Ҳмқҙм–ҙ) л¬¶мқҢм—җм„ң к°ҖмһҘ кёҙ м„ к№Ңм§Җмқҳ мҲҳм§Ғ кұ°лҰ¬лЎң нҒҙлҹ¬мҠӨн„° нӣ„ t лі‘н•©(rhoBin кІҪкі„В·лҜём„ё мҳӨн”„м…Ӣ мӨ‘мІ© мҷ„нҷ”) */
var FRAME_DEF_STEP2A_COLLINEAR_MERGE_BY_LINE_DISTANCE = true;
/** лҸҷмқј мқјм§Ғм„  мң„ мӮҙм§қ лІҢм–ҙм§„ мқҙмӨ‘м„ : лІ•м„  л°©н–Ҙ мқҙ кұ°лҰ¬(mm) мқҙлӮҙл©ҙ н•ң лҚ©м–ҙлҰ¬(л°ҙл“ңВ·мҲҳм§Ғ нҒҙлҹ¬мҠӨн„° кіөнҶө). */
var FRAME_DEF_STEP2A_COLLINEAR_NEAR_STACK_MM = 10;

/**
 * BY_LINE_DISTANCE мҲҳм§Ғ нҒҙлҹ¬мҠӨн„° л°ҳкІҪВ·rho л°ҙл“ң мҠӨмјҖмқј: `COLLINEAR_NEAR_STACK_MM`.
 * @param tol нҳём¶ңл¶Җ мӢңк·ёлӢҲмІҳ мң м§Җ.
 */
function frameDef2aCollinearLineDistMaxFromTolMm(tol) {
  var ns = (typeof FRAME_DEF_STEP2A_COLLINEAR_NEAR_STACK_MM === 'number' && isFinite(FRAME_DEF_STEP2A_COLLINEAR_NEAR_STACK_MM))
    ? FRAME_DEF_STEP2A_COLLINEAR_NEAR_STACK_MM : 10;
  return Math.max(4, ns);
}

function frameDefMergeCollinearOverlappingSegsFor2aChainJoin(joinCandArr, tol) {
  var src = Array.isArray(joinCandArr) ? joinCandArr : [];
  if (!src.length) return src;
  if (typeof FRAME_DEF_STEP2A_COLLINEAR_MERGE_FOR_CHAIN_JOIN === 'boolean' && !FRAME_DEF_STEP2A_COLLINEAR_MERGE_FOR_CHAIN_JOIN) return src;
  function cmp2aStableSegFinish(sa, sb) {
    if (sa === sb) return 0;
    if (!sa) return -1;
    if (!sb) return 1;
    var ea = Number(sa.ent_id) || 0, eb = Number(sb.ent_id) || 0;
    if (ea !== eb) return ea < eb ? -1 : 1;
    var ia = String(sa.id != null ? sa.id : ''), ib = String(sb.id != null ? sb.id : '');
    if (ia !== ib) return ia < ib ? -1 : (ia > ib ? 1 : 0);
    var sia = Number(sa.seg_index), sib = Number(sb.seg_index);
    sia = isFinite(sia) ? sia : -1;
    sib = isFinite(sib) ? sib : -1;
    return sia - sib;
  }
  function cmp2aPoolByLenDesc(a, b) {
    var dl = (Number(b.len) || 0) - (Number(a.len) || 0);
    if (Math.abs(dl) > 1e-9) return dl > 0 ? 1 : -1;
    var ts = (Number(a.t_start) || 0) - (Number(b.t_start) || 0);
    if (Math.abs(ts) > 1e-9) return ts < 0 ? -1 : (ts > 0 ? 1 : 0);
    return cmp2aStableSegFinish(a.seg, b.seg);
  }
  function cmp2aBatchByTStartAsc(a, b) {
    var ds = (Number(a.t_start) || 0) - (Number(b.t_start) || 0);
    if (Math.abs(ds) > 1e-6) return ds < 0 ? -1 : (ds > 0 ? 1 : 0);
    var dl = (Number(b.len) || 0) - (Number(a.len) || 0);
    if (Math.abs(dl) > 1e-9) return dl > 0 ? 1 : -1;
    return cmp2aStableSegFinish(a.seg, b.seg);
  }
  var tTol = Math.max(1, Number(tol) || 25);
  var gapMm = (typeof FRAME_DEF_STEP2A_COLLINEAR_MERGE_GAP_MM === 'number' && isFinite(FRAME_DEF_STEP2A_COLLINEAR_MERGE_GAP_MM))
    ? Math.max(0, FRAME_DEF_STEP2A_COLLINEAR_MERGE_GAP_MM)
    : (tTol * 1.5);
  gapMm = Math.max(gapMm, tTol * 2);
  var outPass = [];
  var axisStepDeg = (typeof FRAME_DEF_STEP2A_COLLINEAR_MERGE_AXIS_STEP_DEG === 'number' && isFinite(FRAME_DEF_STEP2A_COLLINEAR_MERGE_AXIS_STEP_DEG))
    ? Math.max(2, FRAME_DEF_STEP2A_COLLINEAR_MERGE_AXIS_STEP_DEG)
    : 6;
  var axisStep = axisStepDeg * Math.PI / 180;
  var rhoStep = (typeof FRAME_DEF_STEP2A_COLLINEAR_MERGE_RHO_STEP_MM === 'number' && isFinite(FRAME_DEF_STEP2A_COLLINEAR_MERGE_RHO_STEP_MM))
    ? Math.max(40, FRAME_DEF_STEP2A_COLLINEAR_MERGE_RHO_STEP_MM)
    : 100;
  var unifyScope = typeof FRAME_DEF_STEP2A_COLLINEAR_MERGE_UNIFY_SCOPE === 'boolean' ? FRAME_DEF_STEP2A_COLLINEAR_MERGE_UNIFY_SCOPE : true;
  var unifyLg = typeof FRAME_DEF_STEP2A_COLLINEAR_MERGE_UNIFY_LAYER_GROUP === 'boolean' ? FRAME_DEF_STEP2A_COLLINEAR_MERGE_UNIFY_LAYER_GROUP : false;
  var byLineDist = typeof FRAME_DEF_STEP2A_COLLINEAR_MERGE_BY_LINE_DISTANCE === 'boolean' ? FRAME_DEF_STEP2A_COLLINEAR_MERGE_BY_LINE_DISTANCE : false;
  var lineDistMax = typeof frameDef2aCollinearLineDistMaxFromTolMm === 'function' ? frameDef2aCollinearLineDistMaxFromTolMm(tol) : 10;
  var rhoBandMm = lineDistMax;
  function gKey4(scope, lg, axisBin, rhoBin) {
    return String(scope || '@') + '|' + String(lg || '') + '|' + String(axisBin) + '|' + String(rhoBin);
  }
  function gKeyCoarse(scope, lg, axisBin) {
    return String(scope || '@') + '|' + String(lg || '') + '|' + String(axisBin);
  }
  function perpDistPointToSegLineXY(pt, seg) {
    if (!pt || !seg || !seg.p1 || !seg.p2) return Infinity;
    var px = Number(pt.x) || 0, py = Number(pt.y) || 0;
    var ax = Number(seg.p1.x) || 0, ay = Number(seg.p1.y) || 0, bx = Number(seg.p2.x) || 0, by = Number(seg.p2.y) || 0;
    var dx = bx - ax, dy = by - ay;
    var L = Math.hypot(dx, dy);
    if (L < 1e-6) return Math.hypot(px - ax, py - ay);
    return Math.abs(dy * px - dx * py + bx * ay - by * ax) / L;
  }
  var groups = {};
  for (var i = 0; i < src.length; i++) {
    var s = src[i];
    if (!s || typeof frameDefWallSegIsLineLike !== 'function' || !frameDefWallSegIsLineLike(s)) { outPass.push(s); continue; }
    var len0 = Number(s.len) || 0;
    if (!(len0 > 1e-6) || !s.p1 || !s.p2) { outPass.push(s); continue; }
    var axis = frameDefNormAxis(Math.atan2((s.p2.y || 0) - (s.p1.y || 0), (s.p2.x || 0) - (s.p1.x || 0)));
    var axisStepKey = byLineDist ? axisStep * 2 : axisStep;
    var axisBin = Math.round(axis / axisStepKey);
    var binAxis = frameDefNormAxis(axisBin * axisStepKey);
    var u = { x: Math.cos(binAxis), y: Math.sin(binAxis) };
    var n = { x: -u.y, y: u.x };
    var t1 = frameDefDot(s.p1, u), t2 = frameDefDot(s.p2, u);
    var tStart = Math.min(t1, t2), tEnd = Math.max(t1, t2);
    var rho = frameDefDot(frameDefMid(s), n);
    var rhoBin = Math.round(rho / rhoStep);
    var scopePart = unifyScope ? '@' : String(s.scope_key || '@').trim();
    var lgPart = unifyLg ? '@' : (typeof frameDefWallMergeLayerGroup === 'function' ? frameDefWallMergeLayerGroup(s.layer || '') : String(s.layer || ''));
    /** BY_LINE_DISTANCE: м¶•мқҙ к°ҷмңјл©ҙ н•ң н’Җм—җ лӘЁмқҖ л’Ө мҲҳм§Ғкұ°лҰ¬<=nearStack(кё°ліё 10mm)В·м „мқҙм ҒмңјлЎңл§Ң лі‘н•©. м ҲлҢҖ rhoмқҳ floor л°ҙл“ң нӮӨлҠ” 10mm лҜёл§ҢмқёлҚ°лҸ„ н’Җмқҙ к°Ҳлқјм§ҖлҠ” мҳҲк°Җ мһҲм–ҙ мӮ¬мҡ©н•ҳм§Җ м•ҠмқҢ. */
    var key = byLineDist ? gKeyCoarse(scopePart, lgPart, axisBin) : gKey4(scopePart, lgPart, axisBin, rhoBin);
    if (!groups[key]) groups[key] = [];
    groups[key].push({ seg: s, u: u, t_start: tStart, t_end: tEnd, len: len0, rho: rho, n: n });
  }
  var minKeep = Math.max(12, (typeof FRAME_DEF_STEP2A_JOIN_MIN_SEG_MM === 'number' ? FRAME_DEF_STEP2A_JOIN_MIN_SEG_MM : 15) * 0.75);
  var mergedOut = [];
  var keys = Object.keys(groups).sort();
  var multiRunN = 0;
  var keysWithMultiSeg = 0;
  var maxGroupArr = 0;
  var mergeBatches = [];
  var batchId = 0;
  for (var gki = 0; gki < keys.length; gki++) {
    var gz = groups[keys[gki]];
    var gn = gz ? gz.length : 0;
    if (gn > maxGroupArr) maxGroupArr = gn;
    if (gn >= 2) keysWithMultiSeg++;
  }
  for (var ki = 0; ki < keys.length; ki++) {
    var arr = groups[keys[ki]];
    if (!arr || !arr.length) continue;
    if (byLineDist) {
      var pool = arr.slice();
      while (pool.length) {
        pool.sort(cmp2aPoolByLenDesc);
        var seed = pool.shift();
        if (!seed || !seed.seg) continue;
        var cluster = [seed];
        var remaining = pool;
        pool = [];
        var grewCl = true;
        while (grewCl) {
          grewCl = false;
          for (var pi2 = remaining.length - 1; pi2 >= 0; pi2--) {
            var cand2 = remaining[pi2];
            var midC2 = typeof frameDefMid === 'function' ? frameDefMid(cand2.seg) : null;
            var joinCl = false;
            for (var cj = 0; cj < cluster.length; cj++) {
              if (perpDistPointToSegLineXY(midC2, cluster[cj].seg) <= lineDistMax + 1e-4) {
                joinCl = true;
                break;
              }
            }
            if (joinCl) {
              cluster.push(cand2);
              remaining.splice(pi2, 1);
              grewCl = true;
            }
          }
        }
        for (var rx = 0; rx < remaining.length; rx++) pool.push(remaining[rx]);
        var uSeed = seed.u;
        var batchItems = [];
        for (var ci2 = 0; ci2 < cluster.length; ci2++) {
          var cIt = cluster[ci2];
          var ta = frameDefDot(cIt.seg.p1, uSeed), tb = frameDefDot(cIt.seg.p2, uSeed);
          batchItems.push({ seg: cIt.seg, u: uSeed, t_start: Math.min(ta, tb), t_end: Math.max(ta, tb), len: Number(cIt.len) || 0 });
        }
        mergeBatches.push({ items: batchItems, batchId: batchId++ });
      }
      continue;
    }
    arr.sort(cmp2aBatchByTStartAsc);
    var runs = [];
    for (var ai = 0; ai < arr.length; ai++) {
      var it = arr[ai];
      var s0 = Number(it.t_start) || 0, e0 = Number(it.t_end) || 0;
      if (!(e0 > s0 + 1e-6)) continue;
      if (!runs.length) {
        runs.push({ s: s0, e: e0, items: [it] });
        continue;
      }
      var last = runs[runs.length - 1];
      if (s0 <= (Number(last.e) || 0) + gapMm) {
        if (e0 > (Number(last.e) || 0)) last.e = e0;
        last.items.push(it);
      } else {
        runs.push({ s: s0, e: e0, items: [it] });
      }
    }
    for (var ri0 = 0; ri0 < runs.length; ri0++) {
      mergeBatches.push({ items: runs[ri0].items.slice(), batchId: batchId++ });
    }
  }
  for (var bi = 0; bi < mergeBatches.length; bi++) {
    var arrB = mergeBatches[bi].items;
    var bid = mergeBatches[bi].batchId;
    if (!arrB || !arrB.length) continue;
    arrB.sort(cmp2aBatchByTStartAsc);
    var runsB = [];
    for (var aj = 0; aj < arrB.length; aj++) {
      var itj = arrB[aj];
      var sj = Number(itj.t_start) || 0, ej = Number(itj.t_end) || 0;
      if (!(ej > sj + 1e-6)) continue;
      if (!runsB.length) {
        runsB.push({ s: sj, e: ej, items: [itj] });
        continue;
      }
      var lastB = runsB[runsB.length - 1];
      if (sj <= (Number(lastB.e) || 0) + gapMm) {
        if (ej > (Number(lastB.e) || 0)) lastB.e = ej;
        lastB.items.push(itj);
      } else {
        runsB.push({ s: sj, e: ej, items: [itj] });
      }
    }
    for (var rk = 0; rk < runsB.length; rk++) {
      var run = runsB[rk];
      var ts = Number(run.s) || 0, te = Number(run.e) || 0;
      if (!(te > ts + 1e-6)) continue;
      var items = run.items;
      if (items.length === 1) {
        mergedOut.push(items[0].seg);
        continue;
      }
      multiRunN++;
      var base = items[0].seg;
      var maxL = Number(items[0].len) || 0;
      for (var bx = 1; bx < items.length; bx++) {
        var Lx = Number(items[bx].len) || 0;
        if (Lx > maxL + 1e-6) { maxL = Lx; base = items[bx].seg; }
      }
      var uRun = items[0].u;
      var ord = frameDefOrderedSegmentByAxis(base, uRun);
      if (!ord) {
        for (var fj = 0; fj < items.length; fj++) mergedOut.push(items[fj].seg);
        continue;
      }
      var tS = ord.tStart, tE = ord.tEnd;
      var span = tE - tS;
      if (!(span > 1e-9)) {
        for (var fj2 = 0; fj2 < items.length; fj2++) mergedOut.push(items[fj2].seg);
        continue;
      }
      var p1 = frameDefLerpPoint(ord.start, ord.end, (ts - tS) / span);
      var p2 = frameDefLerpPoint(ord.start, ord.end, (te - tS) / span);
      var lenNew = typeof pointDist === 'function' ? pointDist(p1, p2) : Math.hypot((p2.x || 0) - (p1.x || 0), (p2.y || 0) - (p1.y || 0));
      if (!(lenNew > minKeep)) {
        for (var fj3 = 0; fj3 < items.length; fj3++) mergedOut.push(items[fj3].seg);
        continue;
      }
      var allEids = [];
      for (var cix = 0; cix < items.length; cix++) {
        var cs = items[cix].seg;
        var eids = typeof frameDefSegEntityIds === 'function' ? frameDefSegEntityIds(cs) : null;
        if (eids) for (var ej = 0; ej < eids.length; ej++) allEids.push(eids[ej]);
      }
      var clone = {
        id: String(base.id || '') + ':2amerge:' + String(bid) + ':' + String(rk),
        ent_id: Number(base.ent_id) || 0,
        entity_ids: typeof frameDefUniqueEntityIds === 'function' ? frameDefUniqueEntityIds(allEids) : allEids,
        source_type: String(base.source_type || ''),
        p1: { x: p1.x, y: p1.y },
        p2: { x: p2.x, y: p2.y },
        len: lenNew,
        axis_angle: frameDefNormAxis(Math.atan2(p2.y - p1.y, p2.x - p1.x)),
        seg_index: isFinite(Number(base.seg_index)) ? Number(base.seg_index) : -1,
        source_seg_count: items.length,
        source_closed: base.source_closed === true,
        scope_key: String(base.scope_key || '').trim(),
        layer: String(base.layer || ''),
        by_layer: base.by_layer === true
      };
      if (base.merged_line_count != null) clone.merged_line_count = Number(base.merged_line_count) || 0;
      if (base.merged_poly_count != null) clone.merged_poly_count = Number(base.merged_poly_count) || 0;
      if (base.merged_def_count != null) clone.merged_def_count = Number(base.merged_def_count) || 0;
      mergedOut.push(clone);
    }
  }
  var out = mergedOut.concat(outPass);
  return out;
}

/** м„ л¶„ м¶•м—җ мҲҳм§Ғмқё лқ (нҸҗкіЎм„  мҝјл“ң). signFlip -1мқҙл©ҙ л°ҳлҢҖ нҺё(мҢҚмқҳ л°ҳлҢҖ нҠёлһҷ мӘҪ). ONE_SIDEDл©ҙ p1вҖ“p2к°Җ лқ мқҳ н•ң ліҖ, л°ҳлҢҖ ліҖмқҖ лІ•м„ мңјлЎң 2*halfW. */
function frameDefSegToStripQuadWorld(p1, p2, halfW, signFlip) {
  var hw = Math.max(5, Number(halfW) || 85);
  var sgn = (Number(signFlip) < 0) ? -1 : 1;
  var x1 = Number(p1.x) || 0, y1 = Number(p1.y) || 0, x2 = Number(p2.x) || 0, y2 = Number(p2.y) || 0;
  var dx = x2 - x1, dy = y2 - y1;
  var len = Math.hypot(dx, dy);
  if (len < 1e-4) return null;
  var nx = (-dy / len) * sgn, ny = (dx / len) * sgn;
  var oneSided = typeof FRAME_DEF_STEP2A_OPEN_STRIP_ONE_SIDED === 'boolean' ? FRAME_DEF_STEP2A_OPEN_STRIP_ONE_SIDED : true;
  if (oneSided) {
    return [
      { x: x1, y: y1 },
      { x: x2, y: y2 },
      { x: x2 + nx * (2 * hw), y: y2 + ny * (2 * hw) },
      { x: x1 + nx * (2 * hw), y: y1 + ny * (2 * hw) }
    ];
  }
  return [
    { x: x1 + nx * hw, y: y1 + ny * hw },
    { x: x2 + nx * hw, y: y2 + ny * hw },
    { x: x2 - nx * hw, y: y2 - ny * hw },
    { x: x1 - nx * hw, y: y1 - ny * hw }
  ];
}

function frameDefSegOnWallTrack(seg, track) {
  if (!seg || !track || !Array.isArray(track.segments)) return false;
  for (var i = 0; i < track.segments.length; i++) {
    if (track.segments[i] === seg) return true;
  }
  return false;
}
/** 2a ліөлҸ„: мЎ°мқёмңјлЎң мғҲлЎң мғқкёҙ м„ёк·ёлҠ” нҠёлһҷкіј к°қмІҙ м°ёмЎ°к°Җ лӢӨлҘј мҲҳ мһҲмқҢ вҶ’ мӨ‘м җВ·нҠёлһҷ лӮҙ м„ёк·ём—җ лҢҖн•ң к·јм ‘мңјлЎң ліҙмҷ„ */
function frameDefSegGeomCloseToWallTrack2a(seg, track, tolMm) {
  if (!seg || !seg.p1 || !seg.p2 || !track || !Array.isArray(track.segments)) return false;
  var mx = ((Number(seg.p1.x) || 0) + (Number(seg.p2.x) || 0)) * 0.5;
  var my = ((Number(seg.p1.y) || 0) + (Number(seg.p2.y) || 0)) * 0.5;
  var pt = { x: mx, y: my };
  var tlim = Math.max(35, Number(tolMm) || 160);
  for (var i = 0; i < track.segments.length; i++) {
    var g = track.segments[i];
    if (!g || !g.p1 || !g.p2) continue;
    var pr = typeof frameDefPointToSegmentProjection === 'function' ? frameDefPointToSegmentProjection(pt, g) : null;
    if (pr && (Number(pr.dist) || 0) <= tlim) return true;
  }
  return false;
}
