  var useMeasGap = typeof FRAME_DEF_STEP2A_V2_OPPOSITE_THICKNESS_USE_MEASURED_GAP === 'boolean' ? FRAME_DEF_STEP2A_V2_OPPOSITE_THICKNESS_USE_MEASURED_GAP : true;
