  var axisPad = Math.max(0, typeof FRAME_DEF_STEP2A_V2_OPPOSITE_OVERLAP_AXIS_PAD_MM === 'number' ? FRAME_DEF_STEP2A_V2_OPPOSITE_OVERLAP_AXIS_PAD_MM : 0);
