  var thU = Math.max(FRAME_DEF_WALL_MIN_THICKNESS_MM, Math.min(FRAME_DEF_WALL_MAX_THICKNESS_MM, Number(thicknessFullMm) || 170));
  var gn = (typeof gridDivOverride === 'number' && gridDivOverride >= 2)
