      rows: rowsCopy,
      totalP: dSrc.totalP,
      totalN: dSrc.totalN,
      totalQuadAreaP: dSrc.totalQuadAreaP,
      totalQuadAreaN: dSrc.totalQuadAreaN,
      coverageP: dSrc.coverageP,
      coverageN: dSrc.coverageN,
