      var sumWk = (Number(dWk.totalP) || 0) + (Number(dWk.totalN) || 0);
      if (sumWk >= weakThr) continue;
      var saW = wWk.seg_a;
      var mwx = ((Number(saW.p1.x) || 0) + (Number(saW.p2.x) || 0)) * 0.5;
      var mwy = ((Number(saW.p1.y) || 0) + (Number(saW.p2.y) || 0)) * 0.5;
