      seg_b: { id: baseId + '-0-b', ent_id: entityIds[0] || 0, source_type: 'STEP12-' + sourceKey, p1: fallback.b.p1, p2: fallback.b.p2, len: fallback.b.len, axis_angle: fallback.b.axis_angle },
