    var cx = (x0 + x1) * 0.5, cy = (y0 + y1) * 0.5;
    if (pip({ x: cx, y: cy }, poly)) return true;
    if (frameDefOrthoRectTouchesPolyOutline(poly, x0, y0, x1, y1, coordEps)) return true;
