      seg_a: { id: wid + '-a', ent_id: ow.seg_a && ow.seg_a.ent_id != null ? Number(ow.seg_a.ent_id) || 0 : 0, source_type: 'STEP12-124-SPLIT6', p1: s6a.p1, p2: s6a.p2, len: s6a.len, axis_angle: s6a.axis_angle },
      seg_b: { id: wid + '-b', ent_id: ow.seg_b && ow.seg_b.ent_id != null ? Number(ow.seg_b.ent_id) || 0 : 0, source_type: 'STEP12-124-SPLIT6', p1: s6b.p1, p2: s6b.p2, len: s6b.len, axis_angle: s6b.axis_angle },
      thickness_mm: Number(th6.toFixed(1)),
