  if (!Array.isArray(chain) || chain.length < 3) return { walls: [], debug: emptyDebug('мІҙмқё м—ҶмқҢ') };
  var verts = typeof frameDefChainToVertices === 'function' ? frameDefChainToVertices(chain, tol) : [];
  if (!verts || verts.length < 4) return { walls: [], debug: emptyDebug('кјӯм§“м җ ' + (verts ? verts.length : 0) + 'к°ң') };
  var step6HatchVerts = [];
