    var q1 = { x: s.p1.x * 0.75 + s.p2.x * 0.25, y: s.p1.y * 0.75 + s.p2.y * 0.25 };
    var q2 = { x: s.p1.x * 0.25 + s.p2.x * 0.75, y: s.p1.y * 0.25 + s.p2.y * 0.75 };
    var t1 = pBestThicknessAtPoint(q1, s.inward);
