  var pEnt = typeof frameDefChainEntityIds === 'function' ? frameDefChainEntityIds(chain) : [];
  var pIdBase = 'wall-step12-124ho-' + (pEnt.length ? String(pEnt[0]) : '0');
  var pOut = [];
  var pAdjustedForBoundary = 0;
  var pEndpointFallbackCount = 0;
  var pThicknessSkewCount = 0;
  var pSegAOutsideCount = 0;
