    var msg = '\u26a0 \ud574\uce58 \uaca9\uce68 \ub77c\ubca8 \uc5c6\uc74c \u2192 2a \ubc94 \uc5c6\uc74c \ub610\ub294 \u300c2a \uc7ac\uacc4\uc0b0\u300d \ud6c4 \uccb4\ud06c';
    ctx.strokeText(msg, 12, 12);
